Source code in <code>toomanycells/common.py</code> <pre><code>class JEncoder(json.JSONEncoder):
    def default(self, x):
        if isinstance(x, np.bool_):
            return bool(x)
        elif isinstance(x, np.integer):
            return int(x)
        elif isinstance(x, np.floating):
            return float(x)
        elif isinstance(x, np.ndarray):
            return x.tolist()
        else:
            return super().default(x)
